package com.recettealarm.app;import android.app.*;import android.content.*;import android.os.*;
public class AlarmReceiver extends BroadcastReceiver{static String CH="recette_alarm";public void onReceive(Context c,Intent i){create(c);String note=i.getStringExtra("note");Intent full=new Intent(c,AlarmActivity.class).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK|Intent.FLAG_ACTIVITY_CLEAR_TOP).putExtra("note",note).putExtra("title",i.getStringExtra("title"));PendingIntent pi=PendingIntent.getActivity(c,1,full,PendingIntent.FLAG_IMMUTABLE|PendingIntent.FLAG_UPDATE_CURRENT);Notification.Builder nb = Build.VERSION.SDK_INT>=26 ? new Notification.Builder(c,CH) : new Notification.Builder(c); Notification n=nb.setSmallIcon(android.R.drawable.ic_lock_idle_alarm).setContentTitle("Recette Alarm - Anti-Brûlure").setContentText(note).setPriority(Notification.PRIORITY_MAX).setCategory(Notification.CATEGORY_ALARM).setFullScreenIntent(pi,true).setOngoing(true).build();((NotificationManager)c.getSystemService(Context.NOTIFICATION_SERVICE)).notify(88,n);c.startActivity(full);}static void schedule(Context c,long ms,String note,String title){Intent i=new Intent(c,AlarmReceiver.class).putExtra("note",note).putExtra("title",title);PendingIntent pi=PendingIntent.getBroadcast(c,88,i,PendingIntent.FLAG_IMMUTABLE|PendingIntent.FLAG_UPDATE_CURRENT);AlarmManager am=(AlarmManager)c.getSystemService(Context.ALARM_SERVICE);am.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP,System.currentTimeMillis()+ms,pi);}static void create(Context c){if(Build.VERSION.SDK_INT>=26){NotificationChannel ch=new NotificationChannel(CH,"Alarmes cuisson",NotificationManager.IMPORTANCE_HIGH);ch.setLockscreenVisibility(Notification.VISIBILITY_PUBLIC);((NotificationManager)c.getSystemService(Context.NOTIFICATION_SERVICE)).createNotificationChannel(ch);}}}
